changeSet.sql:
ALTER TABLE core.regions
  ALTER COLUMN source_uuid TYPE VARCHAR(38) USING TRIM(source_uuid);

ALTER TABLE core.districts
  ALTER COLUMN source_uuid TYPE VARCHAR(38) USING TRIM(source_uuid);

ALTER TABLE core.sites
  ALTER COLUMN source_uuid TYPE VARCHAR(38) USING NULLIF(TRIM(source_uuid), '');

